[CmdletBinding()]param([switch]$Check)
$ErrorActionPreference='Stop';$root=(Resolve-Path (Join-Path $PSScriptRoot '../..')).Path;$overlay=Get-Content -Raw (Join-Path $root 'knowledge/context/RULE_ROUTE_OVERLAY.json')|ConvertFrom-Json;$seen=@{};$rules=@()
foreach($route in @($overlay.routes)){$key=$route.id;if($seen[$key]){throw "Duplicate route ID: $key"};$seen[$key]=$true;$source=Join-Path $root $route.source;if(-not(Test-Path $source)){throw "Route source missing: $($route.source)"};$text=Get-Content -Raw $source;$line=($text -split "`r?`n"|Where-Object{$_ -match "\|\s*$([regex]::Escape($route.id))\s*\|"}|Select-Object -First 1);if(-not $line){throw "Unknown route ID $key in $($route.source)"};$cells=@($line.Trim('|').Split('|')|ForEach-Object{$_.Trim()});$summary=if($route.id -match '^(?:CQ|LG)-'){$cells[2]}else{$cells[3]};$strength=if($route.id -match '^CQ-'){(($cells[1]-split '/')[1]).Trim()}elseif($route.id -match '^LG-'){$cells[1]}else{$cells[2]};$rules+=[ordered]@{id=$route.id;summary=$summary;source=$route.source;roles=@($route.roles);stages=@($route.stages);productTypes=@($route.productTypes);surfaces=@($route.surfaces);stacks=@($route.stacks);strength=$strength;priority=$route.priority}}
$generated=([ordered]@{schemaVersion=1;generatedFrom=@('knowledge/context/RULE_ROUTE_OVERLAY.json','canonical rule catalogs');rules=@($rules|Sort-Object id)})|ConvertTo-Json -Depth 8;$target=Join-Path $root 'knowledge/context/RULE_ROUTE_INDEX.json';if($Check){if(-not(Test-Path $target) -or (Get-Content -Raw $target).Trim() -ne $generated.Trim()){throw 'RULE_ROUTE_INDEX.json is stale; regenerate it.'};Write-Host 'Rule route index is current.'}else{$generated|Set-Content -LiteralPath $target -Encoding utf8;Write-Host 'Rule route index generated.'}
